function setTag(node,text,css){node.textContent=text;node.className=`tag ${css}`}
function renderLatexNode(node,text,placeholder,opts){
  const c=String(text||"").trim();
  if(!c){node.innerHTML="";node.textContent=placeholder;return}
  if(!c.startsWith("<stem")){
    node.textContent=c;
    if(typeof window.renderMathInElement==="function")try{window.renderMathInElement(node,{delimiters:KATEX_DELIMITERS,throwOnError:false,strict:"ignore"})}catch{}
    return;
  }
  node.innerHTML="";
  const doc=parseStemXmlDoc(c);
  if(!doc){node.textContent="[XML解析错误]: "+c;return}
  const imageResolver=opts&&typeof opts.imageResolver==="function"?opts.imageResolver:()=>"";  
  function processNode(xmlNode,parentEl){
    if(xmlNode.nodeType===Node.TEXT_NODE){parentEl.appendChild(document.createTextNode(xmlNode.nodeValue||""));return}
    if(xmlNode.nodeType!==Node.ELEMENT_NODE)return;
    const tag=String(xmlNode.tagName||"").toLowerCase();
    if(tag==="stem"){Array.from(xmlNode.childNodes).forEach(n=>processNode(n,parentEl));return}
    if(tag==="p"){const p=document.createElement("p");p.className="stem-p";Array.from(xmlNode.childNodes).forEach(n=>processNode(n,p));parentEl.appendChild(p);return}
    if(tag==="image"){
      const ref=(xmlNode.getAttribute("ref")||"").trim();
      const src=imageDataUrl(imageResolver(ref));
      if(src){const img=document.createElement("img");img.className="stem-image";img.src=src;img.alt=ref?`image-${ref}`:"stem-image";parentEl.appendChild(img)}
      else{const note=document.createElement("span");note.className="empty-note";note.textContent=ref?`[配图: ${ref}]`:"[配图]";parentEl.appendChild(note)}
      return
    }
    if(tag==="choices"){
      const mode=(xmlNode.getAttribute("mode")||"single").trim()||"single";
      const div=document.createElement("div");
      div.className=`choices-container ${mode}`;
      Array.from(xmlNode.childNodes).forEach(n=>processNode(n,div));
      parentEl.appendChild(div);
      return
    }
    if(tag==="choice"){
      const key=(xmlNode.getAttribute("key")||"").trim();
      const item=document.createElement("div");
      item.className="choice-item";
      const k=document.createElement("span");
      k.className="choice-key";
      k.textContent=key?`${key}.`:"•";
      const cont=document.createElement("div");
      cont.className="choice-content";
      Array.from(xmlNode.childNodes).forEach(n=>processNode(n,cont));
      item.appendChild(k);item.appendChild(cont);parentEl.appendChild(item);
      return
    }
    if(tag==="blanks"){
      const div=document.createElement("div");
      div.className="blanks-container";
      Array.from(xmlNode.childNodes).forEach(n=>processNode(n,div));
      parentEl.appendChild(div);
      return
    }
    if(tag==="blank"){
      const span=document.createElement("span");
      span.className="blank-item";
      span.textContent=" ";
      const id=(xmlNode.getAttribute("id")||"").trim();
      if(id)span.title=`blank-${id}`;
      parentEl.appendChild(span);
      return
    }
    if(tag==="answer-area"){
      const area=document.createElement("div");
      area.className="answer-area";
      const label=document.createElement("div");
      label.className="answer-area-label";
      label.textContent="解答区";
      const lines=document.createElement("div");
      lines.className="answer-area-lines";
      const raw=Number(xmlNode.getAttribute("lines")||"4");
      const count=Number.isFinite(raw)?Math.max(1,Math.min(12,Math.floor(raw))):4;
      for(let i=0;i<count;i+=1){const line=document.createElement("div");line.className="answer-area-line";lines.appendChild(line)}
      area.appendChild(label);area.appendChild(lines);parentEl.appendChild(area);
      return
    }
    Array.from(xmlNode.childNodes).forEach(n=>processNode(n,parentEl));
  }
  processNode(doc.documentElement,node);
  if(typeof window.renderMathInElement==="function")try{window.renderMathInElement(node,{delimiters:KATEX_DELIMITERS,throwOnError:false,strict:"ignore"})}catch{}
}
