$("stem-editor").addEventListener("click",ev=>{const rmb=ev.target.closest(".block-remove-btn");if(rmb){const bl=rmb.closest(".stem-block");if(bl){bl.remove();editorChanged()}return}if(ev.target.closest(".add-choice-item-btn")){const cb=ev.target.closest(".stem-choices-block");if(cb){const rows=cb.querySelectorAll(".choice-edit-row");const nk=String.fromCharCode(65+rows.length);const ct=cb.querySelector(".choices-items");const rw=document.createElement("div");rw.className="choice-edit-row";const ks=document.createElement("span");ks.className="choice-key-edit";ks.textContent=nk+".";const inp=document.createElement("input");inp.type="text";inp.className="choice-text-input";inp.dataset.key=nk;inp.placeholder="选项 "+nk+" 内容";rw.appendChild(ks);rw.appendChild(inp);ct.appendChild(rw);editorChanged()}return}if(ev.target.closest(".add-blank-item-btn")){const bb=ev.target.closest(".stem-blanks-block");if(bb){const chips=bb.querySelectorAll(".blank-edit-chip");const ni=chips.length+1;const ch=document.createElement("span");ch.className="blank-edit-chip";ch.textContent="\u7a7a"+ni;bb.querySelector(".blanks-edit-items").insertBefore(ch,ev.target.closest(".add-blank-item-btn"));editorChanged()}return}});
