window.qforge.screenshot.onCaptured(async p=>{const imageBase64=p.imageBase64||"";try{if(state.screenshotIntent==="stem-image"){const e=selectedEntry();if(!e)throw new Error("请先选择任务再截图配图");if(!imageBase64)throw new Error("截图数据为空");setStemImageBase64(e,imageBase64);log(`题干配图截图已保存: ${e.questionUuid}`)}else if(state.screenshotIntent==="answer-ocr"){const e=selectedEntry();if(!e)throw new Error("请先选择任务");if(stageOf(e)!=="PENDING_ANSWER")throw new Error("当前阶段不可发起答案 OCR");if(!imageBase64)throw new Error("截图数据为空");const id=await submitOcrForEntry(e,imageBase64,"ANSWER_CONTENT");log(`截图答案OCR已提交: ${e.questionUuid} / ${id}`)}else await createByShot(imageBase64)}catch(e){if(state.screenshotIntent==="stem-image")log(`截图配图失败: ${e.message}`);else if(state.screenshotIntent==="answer-ocr")log(`截图答案OCR失败: ${e.message}`);else log(`截图录题失败: ${e.message}`)}finally{state.screenshotIntent="question-ocr"}});window.qforge.screenshot.onError(p=>{log(`截图服务异常: ${p.message||"未知错误"}`);state.screenshotIntent="question-ocr"});
